import { describe, expect, it } from 'vitest';
import {
  lightTimeSecFromKm,
  marsDelayFromRegime,
  roundTripSecFromKm,
  MARS_RANGE_KM,
} from './mars-light-time';

describe('mars-light-time', () => {
  it('Mars one-way light time matches the three regimes (~3 / ~12.5 / ~22 min)', () => {
    expect(marsDelayFromRegime('opposition')).toBeCloseTo(182.1, 0);
    expect(marsDelayFromRegime('mean')).toBeCloseTo(750.5, 0);
    expect(marsDelayFromRegime('conjunction')).toBeCloseTo(1337.6, 0);
  });

  it('round trip is twice one-way', () => {
    expect(roundTripSecFromKm(MARS_RANGE_KM.mean)).toBeCloseTo(
      2 * lightTimeSecFromKm(MARS_RANGE_KM.mean),
      6,
    );
  });

  it('one-way light time is monotone in distance', () => {
    expect(lightTimeSecFromKm(1e6)).toBeLessThan(lightTimeSecFromKm(2e6));
  });

  it('rejects bad ranges', () => {
    expect(() => lightTimeSecFromKm(-1)).toThrow();
    expect(() => lightTimeSecFromKm(Number.NaN)).toThrow();
  });
});
